    public class ProductController : Controller
    {
        private YourDbContext db = new YourDbContext();

        // GET: /Product/
        public ActionResult Index(int id)
        {
            var product = db.Products.Find(id);
            if (product == null)
                return HttpNotFound();

            var reviews = db.Reviews.Where(r => r.ProductId == id).ToList();
            return View(reviews);
        }

        [HttpPost]
        public ActionResult CreateReview(Review review)
        {
            if (ModelState.IsValid)
            {
                review.UserId = User.Identity.GetUserId();
                review.ProductId = review.ProductId;
                db.Reviews.Add(review);
                db.SaveChanges();
                return RedirectToAction("Index", new { id = review.ProductId });
            }
            return View(review);
        }

        public ActionResult CreateReview(int id)
        {
            var product = db.Products.Find(id);
            if (product == null)
                return HttpNotFound();

            return View(new Review());
        }

        [HttpPost]
        public ActionResult EditReview(Review review)
        {
            if (ModelState.IsValid)
            {
                review.UserId = User.Identity.GetUserId();
                review.ProductId = review.ProductId;
                db.Entry(review).State = EntityState.Modified;
                db.SaveChanges();
                return RedirectToAction("Index", new { id = review.ProductId });
            }
            return View(review);
        }

        public ActionResult EditReview(int id)
        {
            var review = db.Reviews.Find(id);
            if (review == null)
                return HttpNotFound();

            return View(review);
        }

        [HttpPost]
        public ActionResult DeleteReview(int id)
        {
            var review = db.Reviews.Find(id);
            if (review != null)
            {
                db.Reviews.Remove(review);
                db.SaveChanges();
            }
            return RedirectToAction("Index", new { id = review.ProductId });
        }

        public ActionResult DeleteReview(int id, int productId)
